scwin.gr_correctFreight_ontextimageclick = function (rowIndex, columnIndex) {
  let columnId = gr_correctFreight.getColumnID(columnIndex);
  if (columnId == "fcode") {
    udc_ilcomCode_Grid.ilCommonPopUp(scwin.callbackGridFreight, ds_correctionNoticeFreightList.getCellData(rowIndex, "fcode"), ds_correctionNoticeFreightList.getCellData(rowIndex, "fdesc"), 'T', '2', 'Freight Code,Freight Name', '150,170', null, null, '440', '500', null, null, null, "F", 'Freight Search,Freight Code,Freight Name');
    scwin._gridFreightRow = rowIndex;
  }
};
scwin.callbackGridFreight = function (rtnList) {
  let row = scwin._gridFreightRow;
  if (rtnList != null && rtnList.length > 0) {
    ds_correctionNoticeFreightList.setCellData(row, "fcode", rtnList[0]);
    if (rtnList.length > 1) {
      ds_correctionNoticeFreightList.setCellData(row, "fdesc", rtnList[1]);
    }
    if (rtnList.length > 2) {
      ds_correctionNoticeFreightList.setCellData(row, "fint", rtnList[2]);
    }
  }
};
